#include<bits/stdc++.h>
using namespace std;

void f(int x){
    //cout<<x<<'\n';
    if(x==1){
        return;
    }
    if(x==0){
        cout<<"0";
        return;
    }
    string a="";
    while(x){
        int m=x%2;
        x/=2;
        if(m==1){
            a+='1';
        }else{
            a+='0';
        }
    }
    int flag=0;
    for(int i=a.size()-1;i>=0;i--)
    {
       // cout<<a[i];
        if(a[i]=='1'){
            if(flag==1) cout<<"+";
            cout<<"2";
            if(i!=1)cout<<"(";
            f(i);
            if(i!=1) cout<<")";
            flag=1;
        }
    }
    return;

}
int main(){
    int n;
    cin>>n;
    f(n);
    return 0;
}
